func TestMemoryEventStorePurgeWithEmptyChunk(t *testing.T) {
	// Regression test: purge should not panic when the first chunk in a stream
	// is empty (nil), which happens when SSE priming calls Append(nil).
	ctx := context.Background()
	s := NewMemoryEventStore(nil)

	// Open a session and stream.
	s.Open(ctx, "S1", "1")

	// Step 1: Prime with empty data (SSE priming Append(nil)).
	if err := s.Append(ctx, "S1", "1", nil); err != nil {
		t.Fatal(err)
	}

	// Verify state: one empty chunk, nBytes = 0.
	if s.nBytes != 0 {
		t.Fatalf("after nil append, nBytes = %d, want 0", s.nBytes)
	}

	// Step 2: Append a payload large enough to exceed MaxBytes.
	payload := []byte(strings.Repeat("x", 100))
	if err := s.Append(ctx, "S1", "1", payload); err != nil {
		t.Fatal(err)
	}

	// nBytes should now be 100.
	if s.nBytes != 100 {
		t.Fatalf("after 100-byte append, nBytes = %d, want 100", s.nBytes)
	}

	// Step 3: Set max bytes very low, then append more to trigger purge.
	// At this point the dataList is [nil, 100-byte-payload], size=100, nBytes=100.
	s.SetMaxBytes(10)

	// After SetMaxBytes(10), purge runs. The list has size=100 > 10.
	// First iteration: removeFirst on the only dataList (size=100 > 0),
	// which removes the nil leading chunk returning r=0, changed stays false.
	// Second iteration: same condition still, nBytes is still 100 > 10,
	// but now the first element is the 100-byte payload, so it would work.
	// But the bug is: changed stays false after first iteration -> panic!

	// Step 4: Append again to trigger purge. This should NOT panic.
	if err := s.Append(ctx, "S1", "1", []byte("more")); err != nil {
		t.Fatal(err)
	}

	// If we got here, the panic was fixed.
	t.Logf("final state: %s", s.debugString())
}

